UPDATE `blog_column_article` SET `deleted_at`='2026-05-08 23:51:07',`updated_at`='2026-05-08 23:51:07' WHERE `column_id`=9200007;


UPDATE `blog_topic_article` SET `deleted_at`='2026-05-08 23:51:07',`updated_at`='2026-05-08 23:51:07' WHERE `topic_id` IN (9307001, 9307002, 9307003, 9307004, 9307005, 9307006);


UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('分布式系统', '并发编程', '微服务系统与设计', '架构', '架构基础', '架构设计', '算法', '系统设计之商业业务平台', '系统设计之日志系统平台', '系统设计之网关设计', '设计模式');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200007);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9307001, 9307002, 9307003, 9307004, 9307005, 9307006);

